class Solution(object):
    def findPeakGrid(self, mat):
        def find_peak_col(col):
            max_row = 0
            for i in range(len(mat)):
                if mat[i][col] > mat[max_row][col]:
                    max_row = i
            return max_row
        left, right = 0, len(mat[0]) - 1
        while left < right:
            mid = (left + right) // 2
            peak_row = find_peak_col(mid)
            if mat[peak_row][mid] < mat[peak_row][mid + 1]:
                left = mid + 1
            else:
                right = mid
        peak_row = find_peak_col(left)
        return [peak_row, left]
